---@type ModelActivity
local ModelActivity = ModelActivity

function ModelActivity:InitExtraActivity()
    self._model13ReqConfigMap = {}
    self._model13ReqPageMap = {}
    self._model13ExtraInfoMap = {}

    ---@type table<number,StructActLotteryInfo>
    self._actLotteryInfoMap = {}


    self:ModelNetMsgRecv(LProtoIds.ActSelLotteryRoundResp, function(...)
        self:OnActSelLotteryRoundResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.ActSelLotteryGuaranteeResp, function(...)
        self:OnActSelLotteryGuaranteeResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.ActLotteryResp, function(...)
        self:OnActLotteryResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.ActLotteryInfoResp, function(...)
        self:OnActLotteryInfoResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.ActLotteryLogResp, function(...)
        self:OnActLotteryLogResp(...)
    end)

    self:ModelEventRecv(EventNames.ON_CHARGE_MONEY_CHANGE,function(...) self:OnChargeMoneyChange(...) end)
    self:ModelEventRecv(EventNames.PLAYER_VIP_LEVEL_CHANGE,function(...) self:OnPlayerVipChange(...) end)
end

function ModelActivity:StartInitModel13Config(sid)
    local activityData = self:GetWebActivityDataById(sid)
    if not activityData then
        self._model13ReqConfigMap[sid] = 1
        self:ReqActivityConfigData(sid)
        return
    end
    self:OnModel13ConfigDataResp(sid)
end

function ModelActivity:InitModel13ConfigExtra(sid)
    local activityData = self:GetWebActivityDataById(sid)
    if not activityData then
        self._model13ReqConfigMap[sid] = 1
        self:ReqActivityConfigData(sid)
        return
    end
    local config = activityData.config
    local extraRewardGear = config.extraRewardGear
    if string.isempty(extraRewardGear) then return end

    local name = gModelActivity:GetLngNameById(config.name)
    local descript = ModelNormalActivity.Descript_TimeLimit
    local regTime = gModelPlayer:GetRegTime()
    local extraInfo = {}
    local extraRewardGears = string.split(extraRewardGear,"|")
    local extraRewardTime1 = string.split(config.extraRewardTime1,"|")
    local extraReward = string.split(config.extraReward,"|")
    local extraRewardTime2 = string.split(config.extraRewardTime2,"|")
    local extraRewardTipId = string.split(config.extraRewardTipId,"|")
    local extraRewardText = string.split(config.extraRewardText,"|")
    for i,v in ipairs(extraRewardGears) do
        v = checknumber(v)
        local createRoleHour = checknumber(extraRewardTime1[i])
        local createRoleTime = createRoleHour * 3600

        local createRoleTipHour = checknumber(extraRewardTime2[i])
        local showTipTime = createRoleTipHour * 3600

        local rewardList = LxDataHelper.ParseItem_3List(extraReward[i])
        for idx,val in ipairs(rewardList) do
            val.descript = descript
        end

        extraInfo[v] = {
            regTime = regTime,
            createRoleHour = createRoleHour,
            createRoleTime = createRoleTime,
            createRoleEndTime = regTime + createRoleTime,
            rewardList = rewardList,
            createRoleTipHour = createRoleTipHour,
            showTipTime = showTipTime,
            showTipEndTime = regTime + showTipTime,
            showTipId = checknumber(extraRewardTipId[i]),
            rewardText = extraRewardText[i],
            name = name
        }
    end

    self._model13ExtraInfoMap[sid] = {
        extraInfo = extraInfo,
        isShow = false,
    }
    return true
end

function ModelActivity:CheckIsModel13ReqConfig(sid)
