    if not status then return false end
    return status == 1
end

function ModelActivity:GetModel13ConfigExtra(sid)
    if not self._model13ExtraInfoMap[sid] then
        if not self:InitModel13ConfigExtra(sid) then return end
    end
    return self._model13ExtraInfoMap[sid]
end

function ModelActivity:GetModel13ConfigExtraInfo(sid)
    local extraData = self:GetModel13ConfigExtra(sid)
    if not extraData then return end
    return extraData.extraInfo
end

function ModelActivity:OnModel13ConfigDataResp(sid)
    self._model13ReqConfigMap[sid] = 2

    local disposeModel13ConfigMap = self._disposeModel13ConfigMap
    if not disposeModel13ConfigMap then
        disposeModel13ConfigMap = {}
        self._disposeModel13ConfigMap = disposeModel13ConfigMap
    end
    if disposeModel13ConfigMap[sid] then return end

    local extraInfo = self:GetModel13ConfigExtraInfo(sid)
    if not extraInfo then
        self:InitModel13ConfigExtra(sid)
        extraInfo = self:GetModel13ConfigExtraInfo(sid)
    end
    if not extraInfo then return end

    self._model13ReqPageMap[sid] = 1
    self:OnActivityPageReq(sid)
end

function ModelActivity:CheckIsModel13ReqPage(sid)
