    if not status then return false end
    return status == 1
end

function ModelActivity:OnModel13PageDataResp(sid,pages)
    self._model13ReqPageMap[sid] = 2

    local extraInfo = self:GetModel13ConfigExtraInfo(sid)
    if not extraInfo then return end

    local pop = LPlayerPrefs.recordModel13Pop or ""
    local pops = string.split(pop,"|")
    for i,v in ipairs(pops) do
        if checknumber(v) == sid then
            self._model13ReqPageMap[sid] = 3
            return
        end
    end


    local pageMap = {}
    for i,v in ipairs(pages) do
        ---@type StructActivityPage
        local page = self:GenerateActivePageDataFromPb(v)
        pageMap[page.pageId] = page
    end

    ---@type StructActivityPage
    local pageBuy = pageMap[1]
    if not pageBuy then return end

    ---@type StructActivityEntry[]
    local entry = pageBuy.entry
    if not entry or #entry < 1 then return end

    local curPops = {}
    ---@type boolean 按照发行要求调整，不弹提示弹窗，直接弹窗购买弹窗
    local isIssue = true
    local needShowTips
    local needTipCnt = 0
    local needTipList = {}
    for i,v in ipairs(entry) do
        local entryId = v.entryId
        local entryInfo = extraInfo[entryId]
        if entryInfo then
            ---@type StructMarketData
            local MarketData = v.MarketData
            if MarketData then
                local loseCnt = MarketData.personalGoal - MarketData.personal
                needShowTips = loseCnt > 0 and self:CheckInModel13CRTip(sid,entryId) == 0
                if needShowTips then
                    needTipCnt = needTipCnt + 1
                    table.insert(curPops,sid)

                    if isIssue then
                        table.insert(needTipList,{
                            wndPara = {
                                uiName = "UIPkBuyPopBig",
                                sid = sid,
                                entry = entry,
                                grade = i,
                                index = entryId,
                                modelActivityType = ModelActivity.MODEL_PASSB,
                                titleName = entryInfo.name,
                                defaultSort = 7223483,
                            }
                        })
                    else
                        table.insert(needTipList,{
                            wndPara = {
                                showCDTime = entryInfo.createRoleEndTime,
                                refId = entryInfo.showTipId,
                                para = { entryInfo.name },
                                func = function()
                                    if self:CheckModel13InCRTime(sid,entryId) ~= 0 then
                                        GF.ShowMessage(ccClientText(14221))
                                        return
                                    end
                                    GF.OpenWnd("UIPkBuyPopBig",{
                                        sid = sid,
                                        entry = entry,
                                        grade = i,
                                        index = entryId,
                                        modelActivityType = ModelActivity.MODEL_PASSB,
                                        titleName = entryInfo.name
                                    })
                                end,
                                defaultSort = 7223483,
                            }
                        })
                    end
                    break
                end
            end
        end
    end
    if needTipCnt > 0 then
        for i,v in ipairs(needTipList) do
            if isIssue then
                gModelGeneral:InsertPopActivityWnd(v.wndPara)
            else
                gModelGeneral:InsertPopWndPara(v.wndPara)
            end
        end

        local str = table.concat(curPops,"|")
        LPlayerPrefs.SetRecordModel13Pop(str)
    end

    self._model13ReqPageMap[sid] = 3
end

--- 是否在创角时间内 -1：无配置，-2：超出时间，-3：已购买，0：在时间内
function ModelActivity:CheckModel13InCRTime(sid,entryId)
    local limitTime = self:GetModel13ExtraCREndTime(sid,entryId)
    if not limitTime then return -1 end

    return limitTime >= GetTimestamp() and 0 or -2
end

function ModelActivity:GetModel13ExtraCREndTime(sid,entryId)
    local extraInfo = self:GetModel13ConfigExtraInfo(sid)
    if not extraInfo then return end

    local entryInfo = extraInfo[entryId]
    if not entryInfo then return -1 end

    return entryInfo.createRoleEndTime
end

--- 是否在创角时间内提示 -1：无配置，-2：超出时间，-3：已购买，0：在时间内
function ModelActivity:CheckInModel13CRTip(refId,entryId)
    local extraInfo = self:GetModel13ConfigExtraInfo(refId)
    if not extraInfo then return -1 end

    local entryInfo = extraInfo[entryId]
    if not entryInfo then return -1 end

    --- 不在创角时间内不处理
    if self:CheckModel13InCRTime(refId,entryId) < 0 then return -2 end

    local curTime = GetTimestamp()
    local limitTipTime = entryInfo.showTipEndTime
    local limitCreateRoleTime = entryInfo.createRoleEndTime
    if limitTipTime <= curTime and curTime <= limitCreateRoleTime then
        return 0
    end
    return -2
end



function ModelActivity:GetModel13ConfigRewardList(sid,entryId)
    if not sid or not entryId then return end

    local extraInfo = self:GetModel13ConfigExtraInfo(sid)
    if not extraInfo then return end

    local entryInfo = extraInfo[entryId]
    if not entryInfo then return end

    return entryInfo.rewardList
end

---@return boolean
function ModelActivity:CheckActivityRedPoint(sid,pageId,entryId,status)
    ---@type StructActivity
    local activity = self:GetActivityBySid(sid)
    if not activity then return false end

    status = status or ModelActivity.STATUS_VALID

    if activity.status ~= status then return false end

    ---@type LActivityWebData
    local webData = self:GetWebActivityDataById(sid)
    if not webData then return false end

    local model = activity.model
    if model == ModelActivity.MODEL_ACTIVITY_TYPE_85 then
        if not pageId or not entryId then
            local eModel
            local chunk = webData.chunk or {}
            for i,v in ipairs(chunk) do
                for idx,val in ipairs(v.entries) do
                    eModel = val.eModel or 0
                    if eModel and eModel > 0 then
                        local list = self:GetActivityDataByModelId(eModel,status)
                        if list and #list > 0 then
                            local templateId = val.templateId
                            for index, value in ipairs(list) do
                                local moreInfo = JSON.decode(value.moreInfo)
                                if moreInfo and templateId == moreInfo.templateId then
                                    if gModelRedPoint:GetActivityRedPointPageEntry(value.sid,v.id,val.id) then
                                        return true
                                    end
                                end
                            end
                        end
                    end
                end
            end
            return false
        end

        local entryCfg = self:GetWebActivityEntryData(sid,pageId,entryId)
        if not entryCfg then return false end

        local eModel = entryCfg.eModel or 0
        if eModel < 1 then return false end

        local list = self:GetActivityDataByModelId(eModel,status)
        if not list or #list < 1 then return false end

        ---@type StructActivity
        local tActivity
        local templateId = entryCfg.templateId
        for i, v in ipairs(list) do
            local moreInfo = JSON.decode(v.moreInfo)
            if moreInfo and templateId == moreInfo.templateId then
                tActivity = v
                break
            end
        end
        if not tActivity then return false end

        return self:CheckActivityRedPoint(tActivity.sid)
    elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_165 then
        if gModelRedPoint:CheckActivityShowRed(sid) then return true end

        local moreInfo = JSON.decode(activity.moreInfo)
        local allActivation = moreInfo and moreInfo.allActivation or 0
        if allActivation == 1 then return false end

        local config = webData.config
        local puzzleNums = checknumber(config.puzzleNums)
        if puzzleNums and puzzleNums > 0 then
            local item = LxDataHelper.ParseItem_3(config.puzzleConsume)
            if not item then return false end

            return gModelGeneral:CheckItemEnough(item.itemId,item.itemNum)
        end
    end
    return false
end



