function ModelActivity:OnActLotteryInfoResp(pb)
    local actLotteryInfoMap = self._actLotteryInfoMap
    if not actLotteryInfoMap then
        actLotteryInfoMap = {}
        self._actLotteryInfoMap = actLotteryInfoMap
    end

    local sid = pb.sid
    local data = actLotteryInfoMap[sid]
    if not data then
        data = StructActLotteryInfo:New()
        actLotteryInfoMap[sid] = data
    end
    data:CreateByPb(pb)
    FireEvent(EventNames.ON_ACTLOTTERYINFO,data,sid)
end



