function ModelActivity:OnActLotteryLogResp(pb)
    ---@type StructLotteryLogData[]
    local logDataList = {}
    for i,v in ipairs(pb.logDatas) do
        ---@type StructLotteryLogData
        local data = StructLotteryLogData:New()
        data:CreateByPb(v)
        table.insert(logDataList,data)
    end
    table.sort(logDataList,function(a,b)
        return a.createTime > b.createTime
    end)
    FireEvent(EventNames.ON_ACTLOTTERYLOG,{
        logDataList = logDataList,
    },pb.sid)
end


---@param actData StructActivity
function ModelActivity:CheckIsShowModel34(actData)
    if not actData then return false end

    if not self:CheckActivityMainShow(actData) then return false end

    local actWebData = self:GetWebActivityDataById(actData.sid)
    if not actWebData then return false end

    local config = actWebData.config
    if not config then return false end

    local recharge = config.recharge
    if recharge and recharge > 0 then
        recharge = recharge * 100
        local chargeMoney = gModelPlayer:GetChargeMoney() or 0
        if chargeMoney >= recharge then
            self:PopActivity34(actData)
            return true
        end
    end
    local vipGrade = config.vipGrade
    if vipGrade and vipGrade > 0 then
        local vip = gModelPlayer:GetVipLevel()
        if vip >= vipGrade then
            self:PopActivity34(actData)
            return true
        end
    end
    return false
end

function ModelActivity:PopActivity34(actData)
    if not actData then return end
    local activity34Time = checknumber(LPlayerPrefs.activity34AutoOpen)
    if activity34Time and activity34Time == 0 then
        if not self._model34AutoPop then
            self._model34AutoPop = true
            gModelWndPop:TryOpenPopWnd("UIActivity34", {sid = actData.sid,openStatus = 1})
        end
    end
end

function ModelActivity:OnChargeMoneyChange()
    if self:CheckModel34RP() then
        FireEvent(EventNames.ON_REFRESH_ACTIVITY_MODEL_34)
    end
end

function ModelActivity:OnPlayerVipChange()
    if self:CheckModel34RP() then
        FireEvent(EventNames.ON_REFRESH_ACTIVITY_MODEL_34)
    end
end

function ModelActivity:CheckIsModel34BySid(sid)
    ---@type StructActivity
    local actData = self:GetActivityBySid(sid)
    if not actData then return false end
    if not self:CheckActivityMainShow(actData) then return false end
    local model = actData.model
    local bModel34 = model and model == ModelActivity.MODEL_ACTIVITY_TYPE_34 or false
    if bModel34 then
        self:CheckIsShowModel34(actData)
    end
    return bModel34
end

function ModelActivity:CheckModel34RP()
    local actDatas = self:GetActivityDataByModelId(ModelActivity.MODEL_ACTIVITY_TYPE_34)
    if not actDatas or #actDatas < 1 then return false end

    local actData = actDatas[1]
    if not self:CheckIsShowModel34(actData) then return false end

    local showRP = false
    local activity34Time = checknumber(LPlayerPrefs.activity34Time) or 0
    if activity34Time < 1 then
        showRP = true
    else
        if not LUtil.IsToDay(activity34Time) and GetTimestamp() > activity34Time then
            showRP = true
        end
    end
    return showRP
end

--- 未点击
local MODEL10005_RPSTATUS_0 = 0
--- 已点击
local MODEL10005_RPSTATUS_1 = 1
--- 有未领取的红点
local MODEL10005_RPSTATUS_2 = 2
--- 没有红点
local MODEL10005_RPSTATUS_3 = 3

function ModelActivity:CheckModel10005RP()
    --- 已领取奖励的不显示红点
    if gModelPlayer:InAccoutBindingReward(8) then return false end
    
    local model10005RPStatus = self:GetModel10005RPStatus()
    if model10005RPStatus == MODEL10005_RPSTATUS_0 then
        --- 未点击
        return true
    end
    if model10005RPStatus == MODEL10005_RPSTATUS_2 then
        return true
    end
    return false
end

function ModelActivity:GetModel10005RPStatus()
    if not self._model10005RPStatus then
        self._model10005RPStatus = MODEL10005_RPSTATUS_0
    end
    return self._model10005RPStatus
end

function ModelActivity:SetClickModel10005()
    local model10005RPStatus = self:GetModel10005RPStatus()
    if model10005RPStatus == MODEL10005_RPSTATUS_0 then
        self._model10005RPStatus = MODEL10005_RPSTATUS_1
    end
    local hasGet = false
    --- 已添加到桌面且未领奖
    if gLSdkImpl:CallMethod(LSdkMethod.CheckIsExistShortCut) then
        if not gModelPlayer:InAccoutBindingReward(8) then
            hasGet = true
            self._model10005RPStatus = MODEL10005_RPSTATUS_2
        end
    end
    if not hasGet then
        self._model10005RPStatus = MODEL10005_RPSTATUS_3
    end
end



--   xianding=新英雄抽卡界面 10407027
--   fanchang=返场英雄抽卡界面 10407037
--   chongwu=宠物抽取界面 10407034
function ModelActivity:CheckNeedJumpFeed(feedGameExtra)
    if string.isempty(feedGameExtra) then return end
    local funcId
    if feedGameExtra == "xianding" then
        funcId = 10407027
    elseif feedGameExtra == "fanchang" then
        funcId = 10407037
    elseif feedGameExtra == "chongwu" then
        funcId = 10407034
    end
    if not funcId or not gModelFunctionOpen:CheckIsOpened(funcId) then
        if funcId then
            LogWarn("功能未开放 funcId = "..funcId)
        else
            LogWarn("feedGameExtra未匹配 feedGameExtra = "..feedGameExtra)
        end
        return 
    end

    local cfg = gModelFunctionOpen:GetFunctionOpenCfg(funcId)
    if not cfg then
        LogWarn("缺失 funcId = "..funcId)
        return
    end

    local btnIndex = gModelFunctionOpen:ParseBtnIndex(cfg.btnIndex)
    if not btnIndex then
        return
    end

    local subPage = btnIndex.subPage
    if not subPage or subPage < 1 then
        LogWarn("subPage 不存在")
        return
    end
    --- 这里配置的是跳转到 120 模板里面，现在需要改成跳到外面
    local parentUniJump = string.gsub(subPage,"^120","85")
    subPage = checknumber(parentUniJump)

    local sid = self:GetSidByUniqueJump(subPage)
    if not sid then 
        LogWarn("未找到活动 sid feedGameExtra = "..feedGameExtra)
        return 
    end
    ---@type StructActivity
    local activity = self:GetActivityBySid(sid)
    if not activity then return end

    if activity.status == ModelActivity.STATUS_NO_SHOW then
        return
    end

    local data = {
        funcId = funcId,
        sid = sid,
        subPage = subPage,
    }
    return "UIMotifActEntrance_6",data
end